methods.method:
fun getCurrentTenantId(): String
// Fail-closed: throws exception if tenant context missing
// Use in: command handlers, service methods

fun current(): String?
// Nullable: returns null if tenant context missing
// Use in: defensive checks, optional tenant context

interface.pattern:
data class TenantId(val value: String) {
  init {
    require(value.isNotBlank()) { "Tenant ID cannot be blank" }
    require(value.matches(Regex("[a-zA-Z0-9_-]+"))) { "Tenant ID must be alphanumeric" }
    require(value.length in 1..255) { "Tenant ID length must be 1-255 characters" }
  }
}

standards.standard:
Use Kotest FunSpec for unit tests (NOT JUnit).
Test structure: test("should do X when Y") { ... }
Use io.kotest.matchers.shouldBe for assertions.
